/**
 * A Doubly Linked List, because there aren't enough in the world...
 * this is pretty much a direct JS port of the one wikipedia
 * https://en.wikipedia.org/wiki/Doubly_linked_list
 *
 * For most usage 'insertBeginning' and 'insertEnd' should be enough
 *
 * nodes are expected to something like a POJSO like
 * {
 *   prev: null,
 *   next: null,
 *   something: 'whatever you like'
 * }
 */
declare class Node<T = any> {
    data: T;
    prev: Node<T> | null;
    next: Node<T> | null;
    constructor(data: T);
}
declare class DoublyLinkedList<T = any> {
    head: Node<T> | null;
    tail: Node<T> | null;
    length: number;
    constructor();
    insertBeginning(node: Node<T>): void;
    insertEnd(node: Node<T>): void;
    insertAfter(node: Node<T>, newNode: Node<T>): void;
    insertBefore(node: Node<T>, newNode: Node<T>): void;
    remove(node: Node<T>): void;
    static createNode(data: any): Node<any>;
}

export { DoublyLinkedList, Node };
